import json, re
# load the contents query result from storage file
path = var_call_1HKq7GbP5GFN2vZDyv5dAjAD
with open(path, 'r', encoding='utf-8') as f:
    data = json.load(f)

best = None
for rec in data:
    rp = rec.get('repo_data_description') or ''
    sp = rec.get('sample_path') or ''
    if not sp.lower().endswith('.swift'):
        continue
    if 'non-binary' not in rp.lower():
        continue
    m = re.search(r"(\d+)\s+times", rp)
    if not m:
        # try other phrasing
        m = re.search(r"appearing\s+(\d+)\s+times", rp)
    if not m:
        m = re.search(r"copied\s+(\d+)\s+times", rp)
    if not m:
        continue
    copies = int(m.group(1))
    if best is None or copies > best['copies']:
        best = {
            'id': rec.get('id'),
            'sample_repo_name': rec.get('sample_repo_name'),
            'sample_path': sp,
            'copies': copies,
            'repo_data_description': rp
        }

if best is None:
    result = {}
else:
    result = best

print("__RESULT__:")
print(json.dumps(result))

